function normalize(value:string){return value.replace(/\r\n/g,'\n');}
function isProjectRoot(candidate:string){
  return fs.existsSync(path.join(candidate,'package.json'))
    && fs.existsSync(path.join(candidate,'client','src','GameScene.ts'))
    && fs.existsSync(path.join(candidate,'server','src','rooms','Drop8Room.ts'))
    && fs.existsSync(path.join(candidate,'shared','src','index.ts'));
}
function findProjectRoot(){
  const scriptDir=path.dirname(fileURLToPath(import.meta.url));
  for(const start of [process.cwd(),scriptDir]){
    let current=path.resolve(start);
    for(let depth=0;depth<8;depth++){
      if(isProjectRoot(current))return current;
      const parent=path.dirname(current);if(parent===current)break;current=parent;
    }
  }
  throw new Error('DROP 8 프로젝트 루트를 찾지 못했습니다. 이 TS 파일을 package.json이 있는 프로젝트 최상위 폴더에 넣고 실행하세요.');
}
const root=findProjectRoot();

const appliedMarkers:[string,string][]=[
  ['shared/src/index.ts',PATCH_MARKER],
  ['client/index.html','windowVisibilityOverlay'],
  ['server/src/rooms/Drop8Room.ts',"broadcast('characterDeath'"],
  ['docs/PATCH_NOTES.md','## Refactor 010A Window Visibility & Death Presentation Emergency Hotfix'],
];
if(appliedMarkers.every(([relative,marker])=>{
  const target=path.join(root,relative);
  return fs.existsSync(target)&&normalize(fs.readFileSync(target,'utf8')).includes(marker);
})){
  console.log(`${PATCH_NAME}는 이미 적용되어 있습니다.`);
  console.log('검증 명령: pnpm typecheck && pnpm lint && pnpm test && pnpm build');
  process.exit(0);
}

const requiredMarkers:[string,string][]=[
  ['package.json','"start:lan"'],
  ['shared/src/index.ts','DROP8_REFACTOR_009_WINDOW_TRANSIT'],
  ['shared/src/index.ts','DROP8_REFACTOR_010_WINDOW_VEHICLE_DESTRUCTION'],
  ['shared/src/index.ts','export function targetVisibilitySamples'],
  ['server/src/rooms/schema.ts','export class ExplosionState'],
  ['server/src/rooms/Drop8Room.ts',"onMessage('vaultWindow'"],
  ['client/src/GameScene.ts','targetVisibilitySamples,'],
  ['client/src/main.ts','function showGameNotice'],
  ['client/index.html','<canvas id="scopeOverlay"'],
  ['docs/PATCH_NOTES.md','## Refactor 010 Window Combat & Vehicle Destruction Hotfix'],
];
for(const [relative,marker] of requiredMarkers){
  const target=path.join(root,relative);
  if(!fs.existsSync(target)||!normalize(fs.readFileSync(target,'utf8')).includes(marker)){
    throw new Error(`Refactor 008 + 008A + 009 + 010 기준 파일이 아닙니다: ${relative} / 누락 마커: ${marker}`);
  }
}

function findBlock(lines:string[],block:string[],near:number){
  if(block.length===0)return Math.max(0,Math.min(lines.length,near));
  const matches:number[]=[];
  outer:for(let i=0;i<=lines.length-block.length;i++){
    for(let j=0;j<block.length;j++)if(lines[i+j]!==block[j])continue outer;
    matches.push(i);
  }
  if(matches.length===0)return -1;
  return matches.reduce((best,value)=>Math.abs(value-near)<Math.abs(best-near)?value:best,matches[0]!);
}

function applyUnifiedToText(relative:string,source:string,diff:string){
  const raw=normalize(source),hadFinalNewline=raw.endsWith('\n');
  const lines=raw.split('\n');if(lines.at(-1)==='')lines.pop();
  const diffLines=normalize(diff).split('\n');
  let index=0,offset=0;
  while(index<diffLines.length){
    const header=diffLines[index];
    if(!header?.startsWith('@@')){index++;continue;}
    const match=/@@ -(\d+)(?:,(\d+))? \+(\d+)(?:,(\d+))? @@/.exec(header);
    if(!match)throw new Error(`잘못된 패치 hunk: ${relative} / ${header}`);
    const expected=Number(match[1])-1+offset;index++;
    const oldBlock:string[]=[],newBlock:string[]=[];
    while(index<diffLines.length&&!diffLines[index]!.startsWith('@@')){
      const line=diffLines[index]!;
      if(line.startsWith('--- ')||line.startsWith('+++ ')){index++;continue;}
      if(line.startsWith(' ')){oldBlock.push(line.slice(1));newBlock.push(line.slice(1));}
      else if(line.startsWith('-'))oldBlock.push(line.slice(1));
      else if(line.startsWith('+'))newBlock.push(line.slice(1));
      else if(line==='\ No newline at end of file'){index++;continue;}
      index++;
    }
    const at=findBlock(lines,oldBlock,expected);
    if(at<0){
      const already=findBlock(lines,newBlock,expected);
      if(already>=0)continue;
      throw new Error(`패치 기준 불일치: ${relative} / hunk ${match[1]}. Refactor 010 적용 상태인지 확인하세요.`);
    }
    lines.splice(at,oldBlock.length,...newBlock);offset+=newBlock.length-oldBlock.length;
  }
  return lines.join('\n')+(hadFinalNewline?'\n':'');
}

const originalContents=new Map<string,string>();
const nextContents=new Map<string,string>();
for(const [relative,diff] of Object.entries(patches)){
  const target=path.join(root,relative);
  if(!fs.existsSync(target))throw new Error(`필수 파일 없음: ${relative}`);
  const original=fs.readFileSync(target,'utf8');
  originalContents.set(relative,original);
  nextContents.set(relative,applyUnifiedToText(relative,original,diff));
}
console.log(`[Refactor 010A] 전체 diff 사전 검증 완료: ${nextContents.size}개 파일`);
if(process.argv.includes('--dry-run'))process.exit(0);

function uniqueBackupRoot(){
  const base=path.join(root,'patch_backups',BACKUP_NAME);
  if(!fs.existsSync(base))return base;
  const stamp=new Date().toISOString().replace(/[-:TZ.]/g,'').slice(0,14);
  let candidate=`${base}_${stamp}`,suffix=2;
  while(fs.existsSync(candidate))candidate=`${base}_${stamp}_${suffix++}`;
  return candidate;
}
const backupRoot=uniqueBackupRoot();

function resolvePnpmCommand(){
  for(const candidate of ['pnpm','corepack pnpm']){
    const result=spawnSync(`${candidate} --version`,{cwd:root,stdio:'ignore',shell:true});
    if(result.status===0)return candidate;
  }
  throw new Error('pnpm을 실행할 수 없습니다. Node.js 22+와 Corepack/pnpm 설정을 먼저 확인하세요. 파일은 아직 수정되지 않았습니다.');
}
const pnpm=resolvePnpmCommand();

fs.mkdirSync(backupRoot,{recursive:true});
for(const [relative,content] of originalContents){
  const destination=path.join(backupRoot,relative);
  fs.mkdirSync(path.dirname(destination),{recursive:true});
  fs.writeFileSync(destination,content,'utf8');
}
function restoreOriginals(){
  for(const [relative,content] of originalContents){
    const target=path.join(root,relative);fs.mkdirSync(path.dirname(target),{recursive:true});fs.writeFileSync(target,content,'utf8');
  }
}
try{
  for(const [relative,content] of nextContents){
    const target=path.join(root,relative),temporary=`${target}.refactor010a.tmp`;
    fs.writeFileSync(temporary,content,'utf8');fs.renameSync(temporary,target);
  }
}catch(error){
  restoreOriginals();
  throw new Error(`파일 기록 중 오류가 발생해 원본으로 복원했습니다: ${error instanceof Error?error.message:String(error)}`);
}

for(const task of ['typecheck','lint','test','build']){
  console.log(`\n[Refactor 010A] pnpm ${task}`);
  const result=spawnSync(`${pnpm} ${task}`,{cwd:root,stdio:'inherit',shell:true});
  if(result.status!==0){
    restoreOriginals();
    console.error(`\npnpm ${task} 검사 실패로 010A 변경 파일을 원본으로 자동 복원했습니다.`);
    console.error(`백업은 유지됩니다: ${path.relative(root,backupRoot)}`);
    throw new Error(`자동 검증 실패: pnpm ${task}`);
  }
}

console.log(`\n${PATCH_NAME} 적용 및 자동 검증 완료`);
console.log(`수정 파일: ${nextContents.size}개`);
console.log(`백업 위치: ${path.relative(root,backupRoot)}`);
console.log('수동 LAN 확인: pnpm dev:lan');
console.log('확인 항목: 창문 국소 시야 깊이/페이드, 창문 옆 벽 은폐, 원격·AI·로컬 사망 잔상, 관전 카메라 전환');
